#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    for (int tc = 0; tc < T; ++tc) {
        printf("1 - 1\n");
        printf("2 - 4\n");
        printf("3 - 9\n");
        printf("4 - 16\n");
        printf("5 - 25\n");
    }
    return 0;
}

